// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

// Default widths mirror shadcn's sidebar contract. SidebarProvider writes
// these into CSS variables, so they must be literal fallback values rather
// than self-referential `var(--sidebar-width, …)` expressions.
// Values are sourced from DDS tokens: --dds-width-sidebar-{default,expanded,collapsed}.
const SIDEBAR_COOKIE_NAME = 'sidebar_state';
const SIDEBAR_COOKIE_MAX_AGE = 60 * 60 * 24 * 7;
const SIDEBAR_WIDTH = 'var(--dds-width-sidebar-default, 16rem)';
const SIDEBAR_WIDTH_MOBILE = 'var(--dds-width-sidebar-mobile, 18rem)';
const SIDEBAR_WIDTH_ICON = 'var(--dds-width-sidebar-collapsed, 3rem)';
const SIDEBAR_KEYBOARD_SHORTCUT = 'b';

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

type SidebarContextProps = {
  state: 'expanded' | 'collapsed';
  open: boolean;
  setOpen: (open: boolean | ((prev: boolean) => boolean)) => void;
  openMobile: boolean;
  setOpenMobile: (open: boolean) => void;
  isMobile: boolean;
  toggleSidebar: () => void;
};

const SidebarContext = React.createContext<SidebarContextProps | null>(null);

/**
 * A hook that provides access to the sidebar context, including its state and toggle functions.
 * Must be used within a SidebarProvider.
 *
 * ### Return Value
 *
 * | Property         | Type                          | Description                                  |
 * | :--------------- | :---------------------------- | :------------------------------------------- |
 * | _state_          | `"expanded" \| "collapsed"`   | Current sidebar state                        |
 * | _open_           | `boolean`                     | Whether the sidebar is open (desktop)        |
 * | _setOpen_        | `(open: boolean) => void`     | Set the sidebar open state (desktop)         |
 * | _openMobile_     | `boolean`                     | Whether the mobile sidebar sheet is open     |
 * | _setOpenMobile_  | `(open: boolean) => void`     | Set the mobile sidebar sheet open state      |
 * | _isMobile_       | `boolean`                     | Whether the viewport is below mobile breakpoint |
 * | _toggleSidebar_  | `() => void`                  | Toggle the sidebar open/closed               |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * function MyComponent() {
 *   const { state, toggleSidebar } = useSidebar();
 *   return <button onClick={toggleSidebar}>{state}</button>;
 * }
 * ```
 */
function useSidebar() {
  const context = React.useContext(SidebarContext);
  if (!context) {
    throw new Error('useSidebar must be used within a SidebarProvider.');
  }

  return context;
}

// ---------------------------------------------------------------------------
// SidebarProvider
// ---------------------------------------------------------------------------

/**
 * Provides sidebar context to child components. Wraps the application layout to enable sidebar state management.
 *
 * ### Component Props
 *
 * | Prop            | Type                       | Default |
 * | :-------------- | :------------------------- | :------ |
 * | _defaultOpen_   | `boolean`                  | `true`  |
 * | _open_          | `boolean`                  | -       |
 * | _onOpenChange_  | `(open: boolean) => void`  | -       |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <SidebarProvider>
 *   <Sidebar>
 *     <SidebarContent>...</SidebarContent>
 *   </Sidebar>
 *   <SidebarInset>
 *     <main>Page content</main>
 *   </SidebarInset>
 * </SidebarProvider>
 * ```
 */
function SidebarProvider({
  defaultOpen = true,
  open: openProp,
  onOpenChange: setOpenProp,
  className,
  style,
  children,
  ...props
}: React.ComponentProps<'div'> & {
  defaultOpen?: boolean;
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
}) {
  const isMobile = useIsMobile();
  const [openMobile, setOpenMobile] = React.useState(false);

  // This is the internal state of the sidebar.
  // We use openProp and setOpenProp for control from outside the component.
  const [_open, _setOpen] = React.useState(defaultOpen);
  const open = openProp ?? _open;
  const setOpen = React.useCallback(
    (value: boolean | ((value: boolean) => boolean)) => {
      const openState = typeof value === 'function' ? value(open) : value;
      if (setOpenProp) {
        setOpenProp(openState);
      } else {
        _setOpen(openState);
      }

      // Persist the sidebar state in a cookie so it can be restored on the
      // next visit (and on the server in SSR setups).
      if (typeof document !== 'undefined') {
        document.cookie = `${SIDEBAR_COOKIE_NAME}=${openState}; path=/; max-age=${SIDEBAR_COOKIE_MAX_AGE}`;
      }
    },
    [setOpenProp, open]
  );

  // Helper to toggle the sidebar.
  const toggleSidebar = React.useCallback(() => {
    return isMobile ? setOpenMobile(prev => !prev) : setOpen(prev => !prev);
  }, [isMobile, setOpen, setOpenMobile]);

  // Adds a keyboard shortcut (Cmd/Ctrl+B) to toggle the sidebar.
  React.useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      if (
        event.key === SIDEBAR_KEYBOARD_SHORTCUT &&
        (event.metaKey || event.ctrlKey)
      ) {
        event.preventDefault();
        toggleSidebar();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [toggleSidebar]);

  // We add a state so that we can do data-state="expanded" or "collapsed".
  // This makes it easier to style the sidebar with Tailwind classes.
  const state = open ? 'expanded' : 'collapsed';

  const contextValue = React.useMemo<SidebarContextProps>(
    () => ({
      state,
      open,
      setOpen,
      isMobile,
      openMobile,
      setOpenMobile,
      toggleSidebar,
    }),
    [state, open, setOpen, isMobile, openMobile, setOpenMobile, toggleSidebar]
  );

  return (
    <SidebarContext.Provider value={contextValue}>
      <TooltipProvider delayDuration={0}>
        <div
          data-slot="sidebar-wrapper"
          style={cssVars({
            '--sidebar-width': SIDEBAR_WIDTH,
            '--sidebar-width-icon': SIDEBAR_WIDTH_ICON,
            ...style,
          })}
          className={cn(
            'group/sidebar-wrapper flex min-h-svh w-full has-data-[variant=inset]:bg-sidebar',
            className
          )}
          {...props}
        >
          {children}
        </div>
      </TooltipProvider>
    </SidebarContext.Provider>
  );
}

// ---------------------------------------------------------------------------
// Sidebar layout components
// ---------------------------------------------------------------------------

/**
 * The main sidebar container that supports collapsible states and multiple variants.
 *
 * ### Component Props
 *
 * | Prop            | Type                                    | Default       |
 * | :-------------- | :-------------------------------------- | :------------ |
 * | _side_          | `"left" \| "right"`                     | `"left"`      |
 * | _variant_       | `"sidebar" \| "floating" \| "inset"`    | `"sidebar"`   |
 * | _collapsible_   | `"offcanvas" \| "icon" \| "none"`       | `"offcanvas"` |
 *
 *
 * ### Example Usage
 *
 * **Sidebar**
 * ```tsx
 * <Sidebar>
 *   <SidebarHeader />
 *   <SidebarContent>
 *     <SidebarGroup>...</SidebarGroup>
 *   </SidebarContent>
 *   <SidebarFooter />
 * </Sidebar>
 * ```
 *
 * **Floating + Icon Collapsible**
 * ```tsx
 * <Sidebar variant="floating" collapsible="icon">
 *   <SidebarContent>...</SidebarContent>
 * </Sidebar>
 * ```
 *
 * **Inset + Right Side**
 * ```tsx
 * <Sidebar variant="inset" side="right">
 *   <SidebarContent>...</SidebarContent>
 * </Sidebar>
 * ```
 */
function Sidebar({
  side = 'left',
  variant = 'sidebar',
  collapsible = 'offcanvas',
  className,
  children,
  dir,
  ...props
}: React.ComponentProps<'div'> & {
  side?: 'left' | 'right';
  variant?: 'sidebar' | 'floating' | 'inset';
  collapsible?: 'offcanvas' | 'icon' | 'none';
}) {
  const {isMobile, state, openMobile, setOpenMobile} = useSidebar();

  if (collapsible === 'none') {
    return (
      <div
        data-slot="sidebar"
        className={cn(
          'flex h-full w-(--sidebar-width) flex-col bg-sidebar text-sidebar-foreground',
          className
        )}
        {...props}
      >
        {children}
      </div>
    );
  }

  if (isMobile) {
    return (
      <Sheet open={openMobile} onOpenChange={setOpenMobile} {...props}>
        <SheetContent
          dir={dir}
          data-sidebar="sidebar"
          data-slot="sidebar"
          data-mobile="true"
          className="w-(--sidebar-width) bg-sidebar p-0 text-sidebar-foreground [&>button]:hidden"
          style={cssVars({
            '--sidebar-width': SIDEBAR_WIDTH_MOBILE,
          })}
          side={side}
        >
          <SheetHeader className="sr-only">
            <SheetTitle>Sidebar</SheetTitle>
            <SheetDescription>Displays the mobile sidebar.</SheetDescription>
          </SheetHeader>
          <div className="flex h-full w-full flex-col">{children}</div>
        </SheetContent>
      </Sheet>
    );
  }

  return (
    <div
      className="group peer hidden text-sidebar-foreground md:block"
      data-state={state}
      data-collapsible={state === 'collapsed' ? collapsible : ''}
      data-variant={variant}
      data-side={side}
      data-slot="sidebar"
    >
      {/* This is what handles the sidebar gap on desktop */}
      <div
        data-slot="sidebar-gap"
        className={cn(
          'relative w-(--sidebar-width) bg-transparent transition-[width] duration-normal ease-in-out',
          'group-data-[collapsible=offcanvas]:w-0',
          'group-data-[side=right]:rotate-180',
          variant === 'floating' || variant === 'inset'
            ? 'group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)+(--spacing(4)))]'
            : 'group-data-[collapsible=icon]:w-(--sidebar-width-icon)'
        )}
      />
      <div
        data-slot="sidebar-container"
        data-side={side}
        className={cn(
          '@container/sidebar fixed inset-y-0 z-raised hidden h-svh w-(--sidebar-width) transition-[left,right,width] duration-normal ease-in-out data-[side=left]:left-0 data-[side=left]:group-data-[collapsible=offcanvas]:left-[calc(var(--sidebar-width)*-1)] data-[side=right]:right-0 data-[side=right]:group-data-[collapsible=offcanvas]:right-[calc(var(--sidebar-width)*-1)] md:flex',
          // Adjust the padding for floating and inset variants.
          variant === 'floating' || variant === 'inset'
            ? 'p-2 group-data-[collapsible=icon]:w-[calc(var(--sidebar-width-icon)+(--spacing(4))+var(--dds-border-offset))]'
            : 'group-data-[collapsible=icon]:w-(--sidebar-width-icon) group-data-[side=left]:border-r group-data-[side=right]:border-l',
          className
        )}
        {...props}
      >
        <div
          data-sidebar="sidebar"
          data-slot="sidebar-inner"
          className="flex size-full flex-col bg-sidebar group-data-[variant=floating]:rounded-lg group-data-[variant=floating]:shadow-raised group-data-[variant=floating]:ring-1 group-data-[variant=floating]:ring-sidebar-border"
        >
          {children}
        </div>
      </div>
    </div>
  );
}

/**
 * A button that toggles the sidebar open or closed. Renders a toggle icon with screen reader text.
 *
 * ### Component Props
 *
 * Accepts all Button component props.
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <SidebarTrigger />
 * ```
 */
function SidebarTrigger({
  className,
  onClick,
  ...props
}: React.ComponentProps<typeof Button>) {
  const {toggleSidebar} = useSidebar();

  return (
    <Button
      data-sidebar="trigger"
      data-slot="sidebar-trigger"
      variant="ghost"
      size="icon-sm"
      className={cn(className)}
      onClick={event => {
        onClick?.(event);
        toggleSidebar();
      }}
      {...props}
    >
      <PanelLeft />
      <span className="sr-only">Toggle Sidebar</span>
    </Button>
  );
}

/**
 * A thin rail at the sidebar edge that toggles the sidebar on click. Provides a subtle resize-like affordance.
 *
 * ### Component Props
 *
 * Accepts all standard `button` HTML attributes.
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <Sidebar>
 *   <SidebarContent>...</SidebarContent>
 *   <SidebarRail />
 * </Sidebar>
 * ```
 */
function SidebarRail({className, ...props}: React.ComponentProps<'button'>) {
  const {toggleSidebar} = useSidebar();

  return (
    <button
      data-sidebar="rail"
      data-slot="sidebar-rail"
      aria-label="Toggle Sidebar"
      tabIndex={-1}
      onClick={toggleSidebar}
      title="Toggle Sidebar"
      className={cn(
        'absolute inset-y-0 z-floating hidden w-4 transition-all ease-in-out group-data-[side=left]:-right-4 group-data-[side=right]:left-0 after:absolute after:inset-y-0 after:start-1/2 after:w-0.5 hover:after:bg-sidebar-border sm:flex ltr:-translate-x-1/2 rtl:-translate-x-1/2',
        'in-data-[side=left]:cursor-w-resize in-data-[side=right]:cursor-e-resize',
        '[[data-side=left][data-state=collapsed]_&]:cursor-e-resize [[data-side=right][data-state=collapsed]_&]:cursor-w-resize',
        'group-data-[collapsible=offcanvas]:translate-x-0 group-data-[collapsible=offcanvas]:after:left-full hover:group-data-[collapsible=offcanvas]:bg-sidebar',
        '[[data-side=left][data-collapsible=offcanvas]_&]:-right-2',
        '[[data-side=right][data-collapsible=offcanvas]_&]:-left-2',
        className
      )}
      {...props}
    />
  );
}

