/**
 * A loading skeleton placeholder for a sidebar menu item, with optional icon skeleton.
 *
 * ### Component Props
 *
 * | Prop       | Type      | Default |
 * | :--------- | :-------- | :------ |
 * | _showIcon_ | `boolean` | `false` |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <SidebarMenu>
 *   {Array.from({ length: 5 }).map((_, i) => (
 *     <SidebarMenuItem key={i}>
 *       <SidebarMenuSkeleton showIcon />
 *     </SidebarMenuItem>
 *   ))}
 * </SidebarMenu>
 * ```
 */
function SidebarMenuSkeleton({
  className,
  showIcon = false,
  ...props
}: React.ComponentProps<'div'> & {
  showIcon?: boolean;
}) {
  // Random width between 50 to 90%.
  const width = React.useMemo(() => {
    return `${Math.floor(Math.random() * 40) + 50}%`;
  }, []);

  return (
    <div
      data-slot="sidebar-menu-skeleton"
      data-sidebar="menu-skeleton"
      className={cn('flex h-8 items-center gap-2 rounded px-2', className)}
      {...props}
    >
      {showIcon && (
        <Skeleton
          className="size-4 rounded"
          data-sidebar="menu-skeleton-icon"
        />
      )}
      <Skeleton
        className="h-4 max-w-(--skeleton-width) flex-1"
        data-sidebar="menu-skeleton-text"
        style={cssVars({'--skeleton-width': width})}
      />
    </div>
  );
}

